// Command Registry - Centralized command registration for the command palette
//
// This module provides a registry of all commands that can be executed via
// the command palette. Commands are defined statically for performance and
// simplicity, with context-aware availability checks.

#include "../include/app.h"
#include "../include/ui_theme.h"
