// External State References (defined in platform.cpp)
// ============================================================================

// Note: We access g_sidebar through accessor functions to avoid structure coupling
// These functions are defined in platform.cpp
extern size_t palette_get_staged_count();
extern size_t palette_get_unstaged_count();
extern size_t palette_get_changed_count();
extern GitRepository g_repo;

// Forward declarations for worker API
extern bool worker_is_busy();

// ============================================================================
// Availability Check Functions
// ============================================================================

// Git operations availability
static bool is_repo_open() {
    return g_repo.is_valid;
}

static bool has_staged_files() {
    return is_repo_open() && palette_get_staged_count() > 0;
}

static bool has_unstaged_files() {
    return is_repo_open() && palette_get_unstaged_count() > 0;
}

static bool has_any_changes() {
    return is_repo_open() && palette_get_changed_count() > 0;
}

static bool is_not_busy() {
    return !worker_is_busy();
}

static bool can_stage_all() {
    return has_unstaged_files() && is_not_busy();
}

static bool can_unstage_all() {
    return has_staged_files() && is_not_busy();
}

static bool can_commit() {
    return has_staged_files() && is_not_busy();
}

static bool can_fetch() {
    return is_repo_open() && is_not_busy();
}

static bool can_push() {
    return is_repo_open() && is_not_busy();
}

static bool can_pull() {
    return is_repo_open() && is_not_busy();
}

static bool can_discard_all() {
    return has_unstaged_files() && is_not_busy();
}

static bool is_head_detached() {
    return is_repo_open() && g_repo.head_detached;
}

static bool can_create_branch_from_head() {
    return is_head_detached() && is_not_busy();
}

