static constexpr size_t g_alias_count = sizeof(g_aliases) / sizeof(g_aliases[0]);

// ============================================================================
// Registry API Implementation
// ============================================================================

void command_registry_init() {
    // Static initialization - nothing to do
    LOG("Command registry initialized with %zu commands and %zu aliases",
        g_command_count, g_alias_count);
}

size_t command_registry_count() {
    return g_command_count;
}

const PaletteCommand* command_registry_get(size_t index) {
    if (index >= g_command_count) return nullptr;
    return &g_commands[index];
}

const PaletteCommand* command_registry_find_by_id(const char* id) {
    if (!id) return nullptr;

    for (size_t i = 0; i < g_command_count; i++) {
        if (strcmp(g_commands[i].id, id) == 0) {
            return &g_commands[i];
        }
    }
    return nullptr;
}

const PaletteCommand* command_registry_find_by_alias(const char* alias) {
    if (!alias) return nullptr;

    // First check if it matches a command ID directly
    const PaletteCommand* direct = command_registry_find_by_id(alias);
    if (direct) return direct;

    // Check aliases
    for (size_t i = 0; i < g_alias_count; i++) {
        if (strcmp(g_aliases[i].alias, alias) == 0) {
            return command_registry_find_by_id(g_aliases[i].command_id);
        }
    }

    return nullptr;
}
